#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.hacker_State)]
    public class Hacker_StateBehaviour : EnemyStateBehaviour
    {
        public Hacker_StateBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        protected override int GetActiveState(Entity enemy)
        {
            if (Hacker.CanHack(enemy))
            {
                return Hacker.STATE_HACK;
            }
            return base.GetActiveState(enemy);
        }
    }
}
